def parse_bib_citekeys(path: Path) -> dict[str, str]:
    if not path.exists():
        return {}
    text = path.read_text(encoding="utf-8", errors="replace")
    mapping: dict[str, str] = {}
    for match in re.finditer(r"@\w+\{([^,\s]+),([\s\S]*?)(?=\n@\w+\{|\Z)", text):
        citekey = match.group(1)
        body = match.group(2)
        for file_match in re.finditer(r"(?:^|\n)\s*file\s*=\s*\{([^}]*)\}", body):
            field = file_match.group(1)
            for rel in re.finditer(r"(?P<path>knowledge/research/[^;}]+?\.pdf)", field):
                mapping[rel.group("path")] = citekey
    return mapping


def read_manifest_path(brain_root: Path) -> Path:
    return brain_root / "_indexes" / "pdf-manifest.jsonl"


def write_manifest(brain_root: Path, entries: list[dict[str, Any]]) -> None:
    path = read_manifest_path(brain_root)
    path.write_text("".join(json.dumps(e, ensure_ascii=False, sort_keys=True) + "\n" for e in entries), encoding="utf-8")


def build_plan(brain_root: Path, vault_root: Path, run_dir: Path, zotero_url: str = DEFAULT_ZOTERO_URL) -> dict[str, Any]:
    entries, invalid = ic.read_manifest(brain_root)
    selected: dict[str, Any] = {}
    collection_target = None
    zotero_error = None
    try:
        selected = get_selected_collection(zotero_url)
        collection_target = find_collection_target(selected, RUN04_COLLECTION)
    except Exception as exc:  # noqa: BLE001
        zotero_error = str(exc)

    papers = research_entries(entries)
    by_sha: dict[str, list[dict[str, Any]]] = defaultdict(list)
    for entry in papers:
        if entry.get("sha256"):
            by_sha[str(entry["sha256"])].append(entry)

    used_citekeys = {str(e.get("citekey")) for e in entries if e.get("citekey")}
    actions = []
    for sha, group in sorted(by_sha.items(), key=lambda item: canonical_for_group(item[1]).get("brain_path", "")):
        existing = next((e for e in group if e.get("zotero_item_key") and e.get("zotero_linked_attachment_key")), None)
        canonical = canonical_for_group(group)
        if existing:
            actions.append(
                {
                    "action": "manifest_note_path_update",
                    "sha256": sha,
                    "brain_path": canonical.get("brain_path"),
                    "citekey": existing.get("citekey"),
                    "zotero_item_key": existing.get("zotero_item_key"),
                    "zotero_linked_attachment_key": existing.get("zotero_linked_attachment_key"),
                    "affected_manifest_rows": len(group),
                }
            )
            continue
        citekey = make_citekey(canonical, used_citekeys)
        actions.append(
            {
                "action": "zotero_import_linked_pdf",
                "sha256": sha,
                "brain_path": canonical.get("brain_path"),
                "title": clean_title(canonical),
                "author": infer_author(canonical),
                "year": infer_year(canonical),
                "doi": canonical.get("doi"),
                "arxiv": canonical.get("arxiv"),
                "planned_citekey": citekey,
                "affected_manifest_rows": len(group),
                "rollback": {
                    "delete_zotero_collection_items": RUN04_COLLECTION,
                    "manifest_restore_from": str(run_dir / "backups" / "pdf-manifest.jsonl.pre-run04"),
                    "delete_note_if_unedited": f"{NOTE_DIR_NAME}/{citekey}.md",
                },
            }
        )

    plan = {
        "run_id": ic.run_id_from_dir(run_dir),
        "created_at": now_iso(),
        "brain_root": str(brain_root),
        "vault_root": str(vault_root),
        "scope": "knowledge/research/**/papers/*.pdf",
        "invalid_manifest_lines": invalid,
        "zotero_url": zotero_url,
        "zotero_collection_name": RUN04_COLLECTION,
        "zotero_collection_target": collection_target,
        "zotero_error": zotero_error,
        "summary": {
            "research_manifest_rows": len(papers),
            "unique_sha": len(by_sha),
            "existing_zotero_sha": sum(1 for a in actions if a["action"] == "manifest_note_path_update"),
            "new_zotero_imports": sum(1 for a in actions if a["action"] == "zotero_import_linked_pdf"),
        },
        "actions": actions,
    }
    return plan


def write_dry_run_csv(plan: dict[str, Any], run_dir: Path) -> Path:
    out = run_dir / "zotero-reconcile-dry-run.csv"
    fields = [
        "brain_path",
        "sha256",
        "zotero_item_key",
        "linked_attachment_key",
        "stored_attachment_key",
        "citekey",
        "recommended_action",
        "affected_manifest_rows",
    ]
    with out.open("w", encoding="utf-8", newline="") as f:
        writer = csv.DictWriter(f, fieldnames=fields)
        writer.writeheader()
        for action in plan["actions"]:
            writer.writerow(
                {
                    "brain_path": action.get("brain_path", ""),
                    "sha256": action.get("sha256", ""),
                    "zotero_item_key": action.get("zotero_item_key", ""),
                    "linked_attachment_key": action.get("zotero_linked_attachment_key", ""),
                    "stored_attachment_key": "",
                    "citekey": action.get("citekey") or action.get("planned_citekey", ""),
                    "recommended_action": action["action"],
                    "affected_manifest_rows": action.get("affected_manifest_rows", ""),
                }
            )
    return out


def import_actions(plan: dict[str, Any], run_dir: Path, chunk_size: int = 20) -> list[dict[str, Any]]:
    imports = [a for a in plan["actions"] if a["action"] == "zotero_import_linked_pdf"]
    target = plan.get("zotero_collection_target")
    if not target:
        raise RuntimeError(f"Zotero collection {RUN04_COLLECTION!r} is missing")
    results = []
    for start in range(0, len(imports), chunk_size):
        chunk = imports[start : start + chunk_size]
        session_id = f"run04-{start // chunk_size + 1}-{int(time.time())}"
        ris = "".join(build_ris_record(action) for action in chunk)
        (run_dir / "logs").mkdir(parents=True, exist_ok=True)
        (run_dir / "logs" / f"{session_id}.ris").write_text(ris, encoding="utf-8")
        status, body = zotero_post(
            plan["zotero_url"],
            f"/connector/import?session={session_id}",
            ris.encode("utf-8"),
            "application/x-research-info-systems",
        )
        if status != 201:
            raise RuntimeError(f"Zotero import failed for {session_id}: HTTP {status} {body[:500]!r}")
        update_status, update_body = zotero_post(
            plan["zotero_url"],
            "/connector/updateSession",
            json.dumps({"sessionID": session_id, "target": target, "tags": ["run-04导入"], "note": ""}, ensure_ascii=False).encode("utf-8"),
        )
        if update_status != 200:
            raise RuntimeError(f"Zotero updateSession failed for {session_id}: HTTP {update_status} {update_body[:500]!r}")
        try:
            payload = json.loads(body.decode("utf-8"))
        except Exception:
            payload = []
        results.append({"session_id": session_id, "count": len(chunk), "http_status": status, "update_status": update_status, "response_items": len(payload) if isinstance(payload, list) else None})
    return results


def write_note(vault_root: Path, entry: dict[str, Any], citekey: str, zotero_item_key: str, attachment_key: str) -> Path:
    note_path = vault_root / NOTE_DIR_NAME / f"{citekey}.md"
    if note_path.exists():
        return note_path
    note_path.parent.mkdir(parents=True, exist_ok=True)
    title = clean_title(entry)
    escaped_title = title.replace('"', '\\"')
    text = f"""---
type: paper-note
title: "{escaped_title}"
citekey: {citekey}
zotero_item_key: {zotero_item_key}
zotero_linked_attachment_key: {attachment_key}
brain_path: {entry.get('brain_path')}
sha256: {entry.get('sha256')}
pdf_status: canonical-linked
mobile_cache: false
doi: {entry.get('doi') or 'null'}
created: {TODAY}
generated_by: Codex run-04 zotero-backfill {TODAY}
tags:
  - needs_review
  - paper
---

# {title}

## 链接

- Zotero: zotero://select/library/items/{zotero_item_key}
- PDF: [[{Path(str(entry.get('brain_path'))).name}]]
- Brain path: `{entry.get('brain_path')}`

## 摘要

needs_review

## 关键点

- needs_review

## Zotero 注释

- needs_review

## 我的理解

- needs_review

## 概念

- needs_review
"""
    note_path.write_text(text, encoding="utf-8")
    return note_path


def apply_plan(brain_root: Path, vault_root: Path, run_dir: Path, plan: dict[str, Any], zotero_db: Path = DEFAULT_ZOTERO_DB) -> dict[str, Any]:
    manifest_path = read_manifest_path(brain_root)
    backup_manifest = run_dir / "backups" / "pdf-manifest.jsonl.pre-run04"
    backup_refs = run_dir / "backups" / "references.bib.pre-run04"
    backup_manifest.parent.mkdir(parents=True, exist_ok=True)
    if not backup_manifest.exists():
        shutil.copy2(manifest_path, backup_manifest)
    refs = brain_root / "_indexes" / "references.bib"
    if refs.exists() and not backup_refs.exists():
        shutil.copy2(refs, backup_refs)
    copy_zotero_db(run_dir, zotero_db, "pre-apply")

    import_results = import_actions(plan, run_dir)

    # Give Better BibTeX and Zotero's notifier queue a chance to flush auto-export state.
    time.sleep(8)
    db_after = copy_zotero_db(run_dir, zotero_db, "post-apply")
    links = read_zotero_links(db_after)

    # BBT export can lag a little behind item writes. Poll briefly, then fall back to planned keys.
    citekeys_by_path: dict[str, str] = {}
    for _ in range(8):
        citekeys_by_path = parse_bib_citekeys(refs)
        if len(citekeys_by_path) >= plan["summary"]["unique_sha"]:
            break
        time.sleep(3)

    entries, invalid = ic.read_manifest(brain_root)
    if invalid:
        raise RuntimeError(f"manifest contains invalid JSON lines: {invalid[:3]}")
    papers = research_entries(entries)
    by_sha: dict[str, list[dict[str, Any]]] = defaultdict(list)
    for entry in papers:
        by_sha[str(entry["sha256"])].append(entry)

    action_by_sha = {a["sha256"]: a for a in plan["actions"]}
    updated_rows = 0
    notes_written = []
    holds = []
    for sha, group in by_sha.items():
        action = action_by_sha.get(sha)
        if not action:
            continue
        canonical = canonical_for_group(group)
        canonical_path = str(canonical.get("brain_path"))
        link = links.get(canonical_path)
        if action["action"] == "manifest_note_path_update":
            link = link or {
                "zotero_item_key": action.get("zotero_item_key"),
                "zotero_linked_attachment_key": action.get("zotero_linked_attachment_key"),
            }
        if not link:
            holds.append({"sha256": sha, "brain_path": canonical_path, "reason": "missing linked attachment after import"})
            continue
        citekey = citekeys_by_path.get(canonical_path) or action.get("citekey") or action.get("planned_citekey")
        if not citekey:
            holds.append({"sha256": sha, "brain_path": canonical_path, "reason": "missing citekey after import"})
            continue
        note_rel = f"{NOTE_DIR_NAME}/{citekey}.md"
        for entry in group:
            entry["citekey"] = citekey
            entry["zotero_item_key"] = link["zotero_item_key"]
            entry["zotero_linked_attachment_key"] = link["zotero_linked_attachment_key"]
            entry["obsidian_note"] = note_rel
            entry["attachment_mode"] = "canonical-linked"
            entry["pdf_status"] = "canonical-linked"
            entry["migration_status"] = "zotero_linked_attachment_verified"
            entry["updated_at"] = now_iso()
            updated_rows += 1
        note = write_note(vault_root, canonical, citekey, str(link["zotero_item_key"]), str(link["zotero_linked_attachment_key"]))
        notes_written.append(str(note))

    write_manifest(brain_root, entries)
    collection_count = read_collection_count(db_after, RUN04_COLLECTION)
    payload = {
        "ok": not holds,
        "import_results": import_results,
        "updated_manifest_rows": updated_rows,
        "notes_written_or_existing": len(notes_written),
        "notes": notes_written,
        "holds": holds,
        "zotero_linked_paths": len(links),
        "references_bib_citekeys_by_path": len(citekeys_by_path),
        "collection_count": collection_count,
        "zotero_db_after_copy": str(db_after),
    }
    ic.write_json(run_dir / "M4-zotero-apply-log.json", payload)
    return payload


def reconcile_only(brain_root: Path, vault_root: Path, run_dir: Path, zotero_db: Path = DEFAULT_ZOTERO_DB) -> dict[str, Any]:
    manifest_path = read_manifest_path(brain_root)
    backup_manifest = run_dir / "backups" / "pdf-manifest.jsonl.pre-reconcile"
    backup_manifest.parent.mkdir(parents=True, exist_ok=True)
    if not backup_manifest.exists():
        shutil.copy2(manifest_path, backup_manifest)

    db_copy = copy_zotero_db(run_dir, zotero_db, "reconcile")
    run04_items = read_run04_collection_items(db_copy)
    links = read_zotero_links(db_copy)
    refs = brain_root / "_indexes" / "references.bib"
    citekeys_by_path = parse_bib_citekeys(refs)

    entries, invalid = ic.read_manifest(brain_root)
    if invalid:
        raise RuntimeError(f"manifest contains invalid JSON lines: {invalid[:3]}")
    papers = research_entries(entries)
    by_sha: dict[str, list[dict[str, Any]]] = defaultdict(list)
    for entry in papers:
        by_sha[str(entry["sha256"])].append(entry)

    updated_rows = 0
    notes_written = []
    holds = []
    covered_sha = set()
    for sha, group in by_sha.items():
        canonical = canonical_for_group(group)
        canonical_path = str(canonical.get("brain_path"))
        zotero = run04_items.get(canonical_path)
        if not zotero:
            existing = next((e for e in group if e.get("zotero_item_key") and e.get("citekey")), None)
            if not existing:
                holds.append({"sha256": sha, "brain_path": canonical_path, "reason": "no Zotero item found"})
                continue
            zotero = {
                "zotero_item_key": existing.get("zotero_item_key"),
                "zotero_linked_attachment_key": existing.get("zotero_linked_attachment_key"),
                "citekey": existing.get("citekey"),
                "brain_path": canonical_path,
            }
        link = links.get(canonical_path)
        citekey = citekeys_by_path.get(canonical_path) or zotero.get("citekey")
        if not citekey:
            holds.append({"sha256": sha, "brain_path": canonical_path, "reason": "missing citekey"})
            continue

        note_rel = f"{NOTE_DIR_NAME}/{citekey}.md"
        attachment_key = link.get("zotero_linked_attachment_key") if link else zotero.get("zotero_linked_attachment_key")
        for entry in group:
            entry["citekey"] = citekey
            entry["zotero_item_key"] = zotero["zotero_item_key"]
            entry["obsidian_note"] = note_rel
            if attachment_key:
                entry["zotero_linked_attachment_key"] = attachment_key
                entry["attachment_mode"] = "canonical-linked"
                entry["pdf_status"] = "canonical-linked"
                entry["migration_status"] = "zotero_linked_attachment_verified"
                entry.pop("zotero_attachment_hold", None)
            else:
                entry.pop("zotero_linked_attachment_key", None)
                entry["attachment_mode"] = "hold-missing-linked-attachment"
                entry["pdf_status"] = "canonical-no-zotero-linked-attachment"
                entry["migration_status"] = "hold_missing_zotero_linked_attachment"
                entry["zotero_attachment_hold"] = "connector_import_created_item_without_linked_attachment"
            entry["updated_at"] = now_iso()
            updated_rows += 1
        note = write_note(vault_root, canonical, citekey, str(zotero["zotero_item_key"]), str(attachment_key or ""))
        notes_written.append(str(note))
        covered_sha.add(sha)
        if not attachment_key:
            holds.append({"sha256": sha, "brain_path": canonical_path, "reason": "missing linked attachment after command-only import"})

    write_manifest(brain_root, entries)
    collection_count = read_collection_count(db_copy, RUN04_COLLECTION)
    payload = {
        "ok": not holds,
        "run04_collection_items": len(run04_items),
        "covered_unique_sha": len(covered_sha),
        "updated_manifest_rows": updated_rows,
        "notes_written_or_existing": len(notes_written),
        "holds": holds,
        "zotero_linked_paths": len(links),
        "references_bib_citekeys_by_path": len(citekeys_by_path),
        "collection_count": collection_count,
        "zotero_db_copy": str(db_copy),
    }
    ic.write_json(run_dir / "M4-zotero-reconcile-log.json", payload)
    return payload


def old_dry_run(args: argparse.Namespace) -> int:
    brain_root = ic.resolve_path(args.brain_root)
    run_dir = args.run_dir
    ic.ensure_run_dir(run_dir)
    entries, invalid = ic.read_manifest(brain_root)
    rows = []
    for e in entries:
        if e.get("kind") == "paper" or e.get("citekey") or e.get("zotero_item_key"):
            rows.append(
                {
                    "brain_path": e.get("brain_path", ""),
                    "sha256": e.get("sha256", ""),
                    "zotero_item_key": e.get("zotero_item_key", ""),
                    "linked_attachment_key": e.get("zotero_linked_attachment_key", ""),
                    "citekey": e.get("citekey", ""),
                    "recommended_action": "existing-linked" if e.get("zotero_linked_attachment_key") else "run-04-review",
                }
            )
    out = run_dir / "zotero-reconcile-dry-run.csv"
    with out.open("w", encoding="utf-8", newline="") as f:
        writer = csv.DictWriter(f, fieldnames=["brain_path", "sha256", "zotero_item_key", "linked_attachment_key", "citekey", "recommended_action"])
        writer.writeheader()
        writer.writerows(rows)
    payload = {"ok": not invalid, "rows": len(rows), "invalid_manifest_lines": invalid, "output": str(out)}
    ic.write_json(run_dir / "M4-zotero-log.json", payload)
    print(payload)
    return 0 if not invalid else 1


def main() -> int:
    parser = ic.parser("M4 Zotero reconciliation/backfill")
    parser.add_argument("--plan", action="store_true", help="write run-04 Zotero dry-run plan")
    parser.add_argument("--apply", action="store_true", help="apply an approved run-04 Zotero plan")
    parser.add_argument("--approved-plan", type=Path, help="approved plan JSON path")
    parser.add_argument("--zotero-url", default=DEFAULT_ZOTERO_URL)
    parser.add_argument("--zotero-db", type=Path, default=DEFAULT_ZOTERO_DB)
    parser.add_argument("--reconcile-only", action="store_true", help="reconcile run-04 Zotero state without importing")
    parser.add_argument("--legacy-dry-run", action="store_true", help="write the pre-run-04 reconciliation CSV only")
    args = parser.parse_args()

    brain_root = ic.resolve_path(args.brain_root)
    vault_root = ic.resolve_path(args.vault_root)
    run_dir = args.run_dir
    ic.ensure_run_dir(run_dir)

    if args.reconcile_only:
        payload = reconcile_only(brain_root, vault_root, run_dir, ic.resolve_path(args.zotero_db))
        print(json.dumps(payload, ensure_ascii=False, indent=2))
        return 0 if payload.get("ok") else 1

    if args.apply:
        if not args.approved_plan:
            print("--apply requires --approved-plan", file=sys.stderr)
            return 2
        plan = ic.read_json(args.approved_plan)
        payload = apply_plan(brain_root, vault_root, run_dir, plan, ic.resolve_path(args.zotero_db))
        print(json.dumps(payload, ensure_ascii=False, indent=2))
        return 0 if payload.get("ok") else 1

    if args.plan:
        plan = build_plan(brain_root, vault_root, run_dir, args.zotero_url)
        plan_path = run_dir / "zotero-run04-plan.json"
        ic.write_json(plan_path, plan)
        csv_path = write_dry_run_csv(plan, run_dir)
        payload = {"ok": not plan.get("invalid_manifest_lines") and bool(plan.get("zotero_collection_target")), "plan": str(plan_path), "csv": str(csv_path), "summary": plan["summary"], "zotero_collection_target": plan.get("zotero_collection_target"), "zotero_error": plan.get("zotero_error")}
        ic.write_json(run_dir / "M4-zotero-log.json", payload)
        print(json.dumps(payload, ensure_ascii=False, indent=2))
        return 0 if payload["ok"] else 1

    return old_dry_run(args)


if __name__ == "__main__":
    raise SystemExit(main())
